        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        23, 
        'Night of the Daemon', 
        'Aaron Rosenberg', 
        'After their adventures in "Day of the Daemon", Alaric and Dietz head south to the Border Princes, the wild, lawless land south of the Empire. Narrowly escaping the clutches of a liche lord, their quest leads them to a citadel full of Chaos cultists. Against such impossible odds, how can our heroes and their new ally get in to defeat the daemon this time?**About the AuthorAaron Rosenberg has written role-playing games, educational books, magazine articles, short stories and novels for White Wolf and the Star Trek: Starfleet Corps of Engineers series. He also runs his own role-playing game publishing company. Aaron lives and works in New York City.', 
        '/uploads/f784d15a-9e10-4241-b8e1-efb22f5536f7.jpg', 
