        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        42, 
        'Dark Apostle', 
        'Anthony Reynolds', 
        'Driven on by dark visions, Dark Apostle Jarulek of the Word Bearers and his force lay waste to the Imperial planet of Tanakreg. After brutally enslaving the population, they set them to work building a monstrous, kilometres-high tower. What is the Word Bearers'' vile purpose, and can they achieve it before the Imperial forces arrive to reclaim the planet?**About the AuthorAnthony Reynolds worked in Games Workshop''s Design Studio in the UK for over five years. He is currently living in Australia, where he works as a freelance writer.', 
        '/uploads/0b22c6ee-4783-484d-986b-88934425ce70.jpg', 
        '/uploads/0b22c6ee-4783-484d-986b-88934425ce70.epub', 
