INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        65, 
        'The Soul Drinker''s Omnibus', 
        'Ben Counter', 
        'The first omnibus in the hugely popular Soul Drinkers series  Genetically engineered superhumans, the Space Marines stand foremost among the warriors who protect the Imperium of Man. The Soul Drinkers have served the Emperor loyally for thousands of years, but their obsessive desire to retrieve an ancient relic throws them into conflict with those they are honour-bound to obey. Faced with an impossible choice, will this proud and noble Chapter back down, or rebel to forge a new destiny for themselves among the stars? This omnibus collects together the novels Soul Drinker, The Bleeding Chalice and Crimson Tears into one action-packed edition!**', 
        '/uploads/9559539f-8e78-4546-b62d-bc646a6793e4.jpg', 
        '/uploads/9559539f-8e78-4546-b62d-bc646a6793e4.epub', 
        'epub', 
