INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        66, 
        'Van Horstmann', 
        'Ben Counter', 
        'Egrimm van Horstmann is the most promising wizard the College of Light has ever seen. Surpassing his mentors and reaching new heights of magical power, he seems destined to lead the College into a bright new future. But van Horstmann’s true motives are sinister – he plans to unleash an ancient dragon imprisoned beneath the college and bring ruin to the Empire, in the name of the Dark Gods.About the AuthorAuthor of the Souldrinkers and Grey Knights series, freelance writer Ben Counter is one of Black Library''s most popular SF authors, and has written RPG supplements and comics books as well as novels. He is a fanatical painter of miniatures, a pursuit which has won him his most prized possession: a prestigious Golden Demon award. He lives in Portsmouth, England, where he can sometimes be seen indulging his enthusiasm for amateur dramatics on the local stage.', 
        '/uploads/b7383ec8-38b2-454c-8510-327a4e71e6ff.jpg', 
        '/uploads/b7383ec8-38b2-454c-8510-327a4e71e6ff.epub', 
