        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        69, 
        'Vermintide', 
        'Bruno Lee', 
        'Product DescriptionWhen Erwin Rohmer is asked to investigate a series of mysterious thefts, he expects nothing more than a challenge to his deductive powers. After all, what risk is there in solving a burglary? However, Erwin is soon plunged into a world of terrifying secrets and monsters. Fleeing for his life, he is forced to turn to the dwarfs in an attempt to stop the verminous skaven race. But will the stubborn dwarfs stoop to helping a lowly manling? About the AuthorBRUNO LEE is an experienced author of genre fiction, with a number of short stories and fantasy novels credited to various pen names. He lives in Arizona.', 
        '/uploads/454936ad-cea2-42c2-b910-f7be480dd76b.jpg', 
        '/uploads/454936ad-cea2-42c2-b910-f7be480dd76b.epub', 
