INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        71, 
        'Blood and Steel', 
        'C. L. Werner', 
        'In the shadowy backstreets of the Old World, vicious bounty hunters ply their lethal trade--catching fugitives for a purse of gold. Brunner is one such ruthless man...but also keeps the closely guarded secret of a former life of luxury and nobility that turned to betrayal and bloodshed. With dark thoughts of vengeance burning away inside him, Brunner must battle to foil the plans of his latest quarry before his nemesis, Krogh, carries out a deadly retribution.', 
        '/uploads/daae791c-5d3a-44f5-a0e2-ff914c32b4df.jpg', 
