INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        76, 
        'Palace of the Plague Lord', 
        'C. L. Werner', 
        'Product DescriptionCL Werner''s latest tale follows the last warrior of a fierce Norse tribe as he sets out on a perilous quest deep into the dreaded Chaos Wastes, a land of magic and madness that lies far to the north of the Empire. Hideous monsters, ravenous daemons, even the landscape itself threaten him and his warrior band on every step of the journey. What price must a mortal pay to steal the treasure of Nurgle - the god of pestilence and decay?', 
        '/uploads/8df79d05-c854-47e6-aac7-5c8a4b0e35da.jpg', 
        '/uploads/8df79d05-c854-47e6-aac7-5c8a4b0e35da.epub', 
