INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        77, 
        'Siege of Castellax', 
        'C. L. Werner', 
        'CL Werner makes his 40K debut with the latest Space Marine Battles novel  The Chaos Space Marines of the Iron Warriors Legion, long renowned as the masters of siege warfare, find the tables turned as they become the target of a massive ork invasion.**About the AuthorThe blazing wastelands of Arizona, home to rattlesnakes, gila monsters, and other unpleasant reptiles such as C. L. Werner. A scheming, twisted little desert rat, he is continually dreaming up new and imaginative rule interpretations of the many tabletop war games he can often be discovered dabbling with. When not finding new ways to ensure the dominion of the Horned Rat, C. L. Werner busies himself with a vast library of horror and sci-fi films and an equally extensive collection of mystery and fantasy books.   His pen has been responsible for such characters as the infamous bounty hunter Brunner, the cunning sorcerer Thyssen Krotzigk, the ruthless witch hunter Mathias Thulmann, and skaven fifth columnist Skrim Gnaw-tail. Like Brunner, it seems there are no creatures too vile for C. L. Werner to have dealings with and he is currently rumored to be haunting old Sylvanina graveyards in search of ''fresh'' material for further tales of dark adventure in the grim Warhammer world.', 
        '/uploads/d1c3063a-325d-4fdd-8108-d39d840677ee.jpg', 
        '/uploads/d1c3063a-325d-4fdd-8108-d39d840677ee.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
