INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        88, 
        'Blood Ravens', 
        'C. S. Goto', 
        'Science fiction. A trilogy of the adventures of the Blood Ravens Space Marines. The Space Marines (or Adeptus Astartes) are elite human soldiers enhanced to superhuman levels through genetic therapy, surgical modifications, and hypnotic indoctrination. The standard Space Marine is the Imperial Space Marine of the Ultramarines chapter, but several variations exist, such as corrupted Chaos Space Marines and the elite Grey Knights.', 
        '/uploads/9a842202-6aad-4b4f-a11f-158b3c105771.jpg', 
        '/uploads/9a842202-6aad-4b4f-a11f-158b3c105771.epub', 
