INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        89, 
        'Dawn of War', 
        'C. S. Goto', 
        'The Third Company of the Blood Ravens Space Marines are fighting tooth and nail with a barbaric ork invasion. The battle is close and bloody, and orks never walk away from a fight. However, even as Blood Ravens Brother-Captain Gabriel Angelos prepares to throw his men forward in a last ditch defence of Tartarus, the mysterious eldar and the traitorous legions of Chaos are observed in the thick of battle. Angelos must guide his brother Marines through a web of deceit and intrigue, secrets that could threaten the entire Blood Ravens Chapter. Pulse-pounding action and adventure, based on the smash hit game from THQ, this is destruction on a planetary scale!Review"Great SF from a very dark future" - Starlog" About the AuthorC S Goto has published short fiction in Inferno! and elsewhere. His work for the Black Library includes the Warhammer 40,000 Dawn of War novels, the Deathwatch series and the Necromunda novel Salvation.', 
        '/uploads/c563a5b3-0601-4949-a832-c90e5dcbbfed.jpg', 
        '/uploads/c563a5b3-0601-4949-a832-c90e5dcbbfed.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
