INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        96, 
        'Bloodspire & Deathwolf (Space Marines Battles)', 
        'C. Z. Dunn, Andy Smillie', 
        'Double audio CD in the popular Space Marine Battles series  The Space Marines take to the skies in this pair of audio dramas. On the world of Axonar, a squad of Blood Angels Scouts scale the dizzying heights of a mighty hive city as their battle-brothers fight far below. Their objective: to open the way for a daring aerial assault that will crack open the city and ensure victory. In the heavens above Luetin Hive, Erik Morkai’s Space Wolves clash with dark eldar raiders, jump-pack clad Blood Claws taking the battle to the aliens’ own infernal airships. But the war will be decided by Morkai himself as he challenges the dark eldar archon to single combat.**About the AuthorC Z Dunn is a man of mystery, domiciled in the East Midlands. His multiplicity of special talents includes many years working in the publishing industry, with a strong leaning towards genre fiction. He is an expert in e-publication, audio production, zombies and cheese. When asked to supply a bio, he replied, ‘C Z Dunn is a thoughtcrime’… a statement to which there is no sensible reply.   Forged from beef and brawn, Andy Smillie emerged from the blacksmith’s fire like a slab of Scottish iron. Hailing from the northern reaches of Glasgow, he crossed the border into England intent on conquest, but instead found gainful employment at Games Workshop. Leaving a trail of carnage in his wake, he eventually settled in the Black Library where he works in marketing by day and as a literary superhero by night. His writing credits include a swathe of articles for various sci-fi, fantasy and hobby magazines. His debut work of fiction, ‘Mountain Eater’, was released in 2011 in the digital publication Hammer and Bolter.', 
        '/uploads/1057c0ee-daed-4182-a8f4-8e8b58fabec3.jpg', 
        '/uploads/1057c0ee-daed-4182-a8f4-8e8b58fabec3.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
