INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        121, 
        'Blood of Asaheim', 
        'Chris Wraight', 
        'Synopsis:Great Space Marine action as the Space Wolves return in hardbackThere is friction amongst the ranks of the Space Wolves Chapter, as the proud Space Marines enter into an uneasy alliance with the devout Sisters of Battle on a war-torn Ecclesiarchy world.Biography:Chris Wraight is a writer of fantasy and science fiction, whose first novel was published in 2008. Since then, he''s published books set in the Warhammer Fantasy, Warhammer 40,000 and Stargate: Atlantis universes. He doesn''t own a cat, dog, or augmented hamster (which technically disqualifies him from writing for Black Library), but would quite like to own a tortoise one day. He''s based in a leafy bit of south-west England, and when not struggling to meet deadlines enjoys running through scenic parts of it.', 
        '/uploads/9ac1df5c-d4ee-43cf-85d0-0c702da9062d.jpg', 
        '/uploads/9ac1df5c-d4ee-43cf-85d0-0c702da9062d.epub', 
        'epub', 
