INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        139, 
        'Bloodstorm', 
        'Dan Abnett', 
        'Product DescriptionSend a monster to kill a monster...Murderer, betrayer, warrior beyond compare...Yet by the cruel standards of the dark elves, Malus Darkblade still has a lot to prove. Possessed by the foul daemon Tz''arkan, Malus only has a year to find five magic artefacts or his soul will be forfeit. To retrieve the Idol of Kolkuth, Malus will have to call on all his cunning and wits to survive a magic labyrinth and defeat its fearsome guardian. The second instalment in the "Darkblade" series, Bloodstorm delves further into the twisted psyche of the cruel and malicious Malus Darkblade. The ultimate antihero returns in the second episode of the "Darkblade" saga. About the AuthorMike Lee was the principal creator and developer for White Wolf Game Studio''s Demon: The Fallen, a role-playing game of fallen angels, infernal glory and the search for redemption. Over the last eight years he has contributed to almost two dozen role-playing games and supplements, including the award-winning Vampire: The Masquerade, Adventure!, Vampire: Dark Ages and Hunter: The Reckoning. His short stories have appeared in the anthologies Dark Tyrants, Inherit the Earth and most recently Del Rey''s Crimson Skies, a collection of novellas based on Microsoft''s pulp-era dogfighting game. An avid wargamer, history buff and devoted fan of two-fisted pulp adventure, Mike lives with his family in the United States. Dan Abnett lives and works in Maidstone, Kent, in England. Well known for his comic work, he has written everything from the Mr Men to the X-Men in the last decade, and received particular acclaim for his five year run on The Legion for DC Comics. He is currently writing Majestic for Wildstorm, and Sinister Dexter and The VCs for 2000 AD. His work for the Black Library includes the popular strips Lone Wolves, Titan and Darkblade, the best-selling Gaunt''s Ghosts novels, and the acclaimed Inquisitor Eisenhorn trilogy.', 
        '/uploads/e6bd0740-03f6-40ba-a27e-3356a63ab8e2.jpg', 
        '/uploads/e6bd0740-03f6-40ba-a27e-3356a63ab8e2.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
