INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        167, 
        'Ravenor Returned', 
        'Dan Abnett', 
        'Product DescriptionDan Abnett, the Black Library''s best-selling author, returns with more tales of Inquisitor Gideon Ravenor and his retinue of lethal operatives. First introduced in Dan''s astonishing Eisenhorn trilogy, Ravenor has left his former master and is now investigating the spread of a unholy psychic substance called flects. As his investigation takes him into the higher echelons of the Imperial hierarchy, it becomes clear that this will be his most dangerous assignment yet. With a huge range of novels behind him, Dan once again shows why he is the master of the Warhammer 40,000 universe. About the AuthorDan Abnett lives and works in Maidstone, Kent, in England. Well known for his comic work, he has written everything from the Mr Men to the X-Men in the last decade. His work for the Black Library includes the popular strips Lone Wolves, Titan and Darkblade, the best-selling Gaunt''s Ghosts novels, and the acclaimed Inquisitor Eisenhorn trilogy.', 
        '/uploads/3e595115-ceba-4219-9467-fd4a32a77386.jpg', 
        '/uploads/3e595115-ceba-4219-9467-fd4a32a77386.epub', 
        'epub', 
