INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        177, 
        'Traitor General', 
        'Dan Abnett', 
        'As the fateof the Sabbat Worlds campaign balances on a knife-edge, the success of the Imperial crusade rests with one high-ranking officer, captured by the dark forces of Chaos. Colonel-Commisar Ibram Gaunt leads a hand-picked strike team deep behind enemy lines to track down an imperial offier who holds strategic knowledge of Warmaster Macaroth''s entire battleplan. Their mission is simple: stop him from revealing his secrets to the enemy - whatever the cost. With their lives forfeit, Gaunt and his team are the key to a mission that will bring either death or glory!**About the AuthorDan Abnett lives and works in Maidstone, Kent, in England. Well known for his comic work, he has written everything from the Mr Men to the X-Men. His work for the Black Library includes the best-selling Gaunt''s Ghosts novels, the acclaimed Inquisitor Eisenhorn series and the Ravenor novels. Traitor General is his sixteenth novel.', 
        '/uploads/55f76da6-9611-49fb-9d0b-f9d43e87d149.jpg', 
        '/uploads/55f76da6-9611-49fb-9d0b-f9d43e87d149.epub', 
        'epub', 
