        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        178, 
        'Warpsword', 
        'Dan Abnett', 
        'Product DescriptionIn the world of Warhammer, no race is as cruel and treacherous as the dark elves, and no member of this race is more infamous than Malus Darkblade. His soul taken forfeit by a daemon, Darkblade must now seek the legendary Warpsword of Khaine or be forever damned. About the AuthorDan Abnett lives and works in Maidstone, Kent, in England. Well known for his comic work, he has written everything from the Mr Men to the X-Men. His work for the Black Library includes the popular strips Lone Wolves, Titan and Darkblade, the best-selling Gaunt''s Ghosts novels, and the acclaimed Inquisitor Eisenhorn trilogy.', 
        '/uploads/f46588ca-8e1b-4b70-80c7-888639be988c.jpg', 
