INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        182, 
        'Sigvald', 
        'Darius Hinks', 
        'Prince Sigvald the Magnificent has struck a pact with his Slaaneshi masters that bestows incredible power and beauty, but drives him to ever greater acts of hedonism. Despite his pre-eminence, the champion of Chaos is tricked into an impossible war with the promise of a powerful artefact to slake his dark desires. After centuries of debauchery, Sigvald rouses his army and leads them to battle against the legions of the Blood God Khorne.Obsessed with the Brass Skull, the object of his misguided yearnings, Sigvald is unaware his enemies are closing in around him. In a hellish quest that drives him across the twisted landscape of the Chaos Wastes and culminates in an epic confrontation, he realises that the lures of Slaanesh can never be sated..', 
        '/uploads/1ec2f62b-eb6b-49a4-87db-2db78a04684f.jpg', 
        '/uploads/1ec2f62b-eb6b-49a4-87db-2db78a04684f.epub', 
