INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        188, 
        'The Death of Antagonis', 
        'David Annandale', 
        'The latest Space Marine Battles novelThe Black Dragons fall upon the world of Antagonis, summoned to combat the plague of undeath that has engulfed the planet. Allying themselves with Inquisitor Werner Lettinger and a force of Sisters of Battle, the Black Dragons endeavour to save the souls of the Imperial citizens who have succumbed to the contagion. But there is more than a mere infection at play – the dread forces of Chaos lie behind the outbreak, and the Black Dragons stand in the way of the Dark Gods’ victory.About the AuthorBy day, David Annandale dons an academic disguise and lectures at a Canadian university on subjects ranging from English literature to horror films and video games, shaping his students into an army of servitors awaiting his signal to rise. He is the author of several thriller and horror novels and the acclaimed short story ‘Carrion Anthem’ for Black Library. He lives with his wife and family and a daemon in the shape of a cat, and is working on several new projects set in the grim darkness of the far future.', 
        '/uploads/f814d2cb-bd51-46be-9e71-e66899b5430b.jpg', 
        '/uploads/f814d2cb-bd51-46be-9e71-e66899b5430b.epub', 
