INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        216, 
        'Shadow Point', 
        'Gordon Rennie', 
        'The Gothic Sector struggles once more against the savage Black Crusade of psychotic Warmaster Abaddon the Despoiler, hell-bent on capturing the Blackstone Fortresses. With these ancient weapons of immeasurable power under his command, the Warmaster would become almost unstoppable. But there are many obstacles standing in his way; amongst these are an uneasy alliance with the cruel Dark Eldar and his ambitious lieutenants vying for power.In a desperate response, the Imperial warship Macharius, commanded by Captain Leoten Semper, is despatched to form its own alliance with the enigmatic eldar. Only by working together can they hope to stop the advancing Chaos hordes. The fragile pacts formed by both sides look set to crumble when it becomes clear that the ultimate prize is at stake -- the universe itself.This action packed sequel to Execution Hour is a true epic, following the exploits of the most evil and powerful characters in the galaxy!', 
        '/uploads/cf13367e-83f8-42a7-aed5-e9ed2903436c.jpg', 
        '/uploads/cf13367e-83f8-42a7-aed5-e9ed2903436c.epub', 
