INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        283, 
        'Forged in Battle', 
        'Justin Hunter', 
        'Readers have long been demanding why there has never been a "Gaunt''s Ghosts for the Warhammer world". The wait is over. Allow us to introduce you to the Ragged Company. Plucked from their everyday lives by the threat of a vast Chaos invasion, this motley band of militiamen seem very shabby and indisciplined alongside the knights and foot troops of the Emperor''s army. But when the daemon hordes of the Ruinous Powers are hurling themselves against the city walls, no one worries about clean uniforms or marching in step. Total war, from the darkest and hardest medieval fantasy setting there is. The first awesome novel in a major new series featuring the Ragged Company!**Review"War-torn tales of loyalty and honour." - SFX" About the AuthorJustin Hunter was born in the Bahamas in 1971. He studied English Language and Medieval Literature at university. He has written several books of his experiences working in the Far East as an aid worker. He currently lives in Ireland.', 
        '/uploads/f3b6a27e-7296-46e4-9295-b14e6ec73905.jpg', 
        '/uploads/f3b6a27e-7296-46e4-9295-b14e6ec73905.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
