INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        309, 
        'Nagash the Unbroken', 
        'Mike Lee', 
        'The powerful necromancer Nagash, having suffered defeat on the battlefield at the hands of the priest kings, is forced to lick his wounds in the mountains of Nehekhara. Over time he rebuilds his strength and finds new allies in the skaven, mutant ratmen that live beneath the earth. In his new lair of Cripple Peak, the necromancer discovers something dark and powerful - warpstone. Coveted by the skaven, this magical rock could make the evil Nagash unstoppable...The Time of Legends series continues with the second book in the Rise of Nagash trilogy, an epic story of power and revenge for all lovers of dark fantasy and the World of Warhammer.**About the AuthorTogether with Dan Abnett, Mike Lee wrote the five-volume Malus Darkblade series. He also wrote the acclaimed Nagash the Sorcerer for Warhammer Time of Legends. Mike was the principal creator and developer for White Wolf Game Studio''s Demon: The Fallen, and he has contributed to almost two dozen role-playing games and supplements over the years. An avid wargamer and devoted fan of pulp adventure, Mike lives in the United States.', 
        '/uploads/bfdc9742-6543-4dec-9ddc-d07cfdee7344.jpg', 
        '/uploads/bfdc9742-6543-4dec-9ddc-d07cfdee7344.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
