INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        310, 
        'The Emperor''s Chosen', 
        'Mike Lee', 
        'When Brother Reinhart hears the Emperor’s voice, he is anointed with the arms and armour of the Emperor’s Champion and sent to fulfil a mighty destiny…  ABOUT THE BOOKA Black Templars story by Mike Lee  Mike Lee gives us a great snapshot of the lives of these devout warriors – he shows us Space Marines aren’t just super-soldiers in powered armour, but somewhat akin to holy men, monkish in their application to their role.– Guy Haley', 
        '/uploads/9ba47f9f-92c0-4883-9108-65546cbf6994.jpg', 
        '/uploads/9ba47f9f-92c0-4883-9108-65546cbf6994.epub', 
