        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        318, 
        'Elfslayer', 
        'Nathan Long', 
        'Product DescriptionDwarf Trollslayer Gotrek and his human companion Felix Jaeger, Warhammer’s most famous pair of heroes, head off to a new adventure facing the terrifying dark elves in the latest novel of this best-selling fantasy series. About the AuthorNathan Long has worked as a screenwriter for fifteen years, during which time he has had three movies made and a handful of live-action and animated TV episodes produced. He has written four novels, and several award-winning short stories. He lives in Hollywood.', 
        '/uploads/b706ebc5-7a13-437d-867b-56761aeab2b8.jpg', 
        '/uploads/b706ebc5-7a13-437d-867b-56761aeab2b8.epub', 
