INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        320, 
        'Manslayer', 
        'Nathan Long', 
        'Product DescriptionNow back in the Empire following their sojourn overseas, Gotrek and Felix head north, to aid the men of the Empire in their fight against the invading Chaos hordes. Stopping off in Nuln, they meet up with dwarf engineer Malakai Makaisson, who is helping the Imperial war effort by transporting cannons to the frontline on his airship, The Spirit of Grungni. After a series of nasty accidents, it becomes clear that saboteurs are at work - can our heroes find the villains in time to save the day? About the AuthorNathan Long has worked as a screenwriter for fifteen years, during which time he has had three movies made and a handful of live-action and animated TV episodes produced. He has written four novels, and several award-winning short stories. He lives in Hollywood.', 
        '/uploads/57137ac2-d7ed-4c9a-a2b4-5262bfcf8fa2.jpg', 
        '/uploads/57137ac2-d7ed-4c9a-a2b4-5262bfcf8fa2.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
