INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        321, 
        'Orcslayer', 
        'Nathan Long', 
        'ReviewNathan Long does a wonderful job of capturing the gritty elements of the dark world of Warhammer fantasy - JT McMahon, Amazon.com Product DescriptionGotrek and Felix arrive back on the southern coast of the Old World to discover that the orcs are running rampant as the Empire fights off a Chaos invasion futher inland. To honour an ancient pledge, Gotrek agrees to help a dwarf prince reclaim his hold from the greenskin invaders who have siezed it, but our intrepid heroes find more than they bargain for in the cold depths of the mountains."A snappy serial in the Tolkein vein draws its heroes and villains from a somewhat tired set of fantasy tropes, but Long''s storytelling ability makes it worthwhile?the narrative maintains the momentum throughout. An engaging if derivative fantasy tale."-Kirkus Discoveries, VNU US Literary Group', 
        '/uploads/906c02c9-6df0-47ab-ae68-7e1191e51103.jpg', 
        '/uploads/906c02c9-6df0-47ab-ae68-7e1191e51103.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
