INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        346, 
        'Reiksguard', 
        'Richard Williams', 
        'The Reiksguard knights are entrusted with the sacred duty of the Emperor''s protection from foes within and without. Under the command of Marshal Kurt Helborg, the Reiksguard live and breathe their code of loyalty, courage, strength and honour. But in the midst of a ruinous war, the young knight Delmar von Reinhardt discovers that this most venerated order hides deadly secrets. Battling an unholy alliance of a goblin warlord and an ogre tyrant, Delmar must unearth the truth no matter which noble knight he should find at its heart.**From the AuthorReiksguard is the kick-off novel in the new Empire Army series in which each novel will highlight a different element of the Empire''s battleline. It features an in-depth look at the inner workings of the Emperor''s own bodyguard, their code, training, and their fighting style, which is based upon the works of real-world late-medieval fightmasters. It also includes famous Empire characters such as Reiksmarshal Kurt Helborg and the Emperor Karl Franz himself. About the AuthorRichard Williams was born in Nottingham, UK and was first published in 2000. He has written fiction for a range of publications on such diverse topics as gang initiation, medieval highwaymen and arcane religions. In his spare time, he is a theatre director and actor. He has written three books, including the novel Relentless published by the Black Library, and had his work printed in Inferno!, The Oxford and Cambridge May Anthologies and in the anthology Status: Deadzone.', 
        '/uploads/53ee4a08-6b25-41b0-a484-4bf51f0e4da3.jpg', 
        '/uploads/53ee4a08-6b25-41b0-a484-4bf51f0e4da3.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
