INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        347, 
        'Relentless', 
        'Richard Williams', 
        'In the cold reaches of space, the mighty and ancient battleships of the Imperial Navy protect mankind from their galactic enemies, charged with the safety of the Imperial space lanes. First Officer Ward, of the Imperial Navy vessel Relentless, is less than pleased when a new commander, hardliner Captain Becket, is appointed. To protect his own corrupt schemes and ambitions, he ruthlessly arranges to have Becket assassinated. Unbeknown to him, the new captain manages to survive, and embarks on a campaign to fight his way back up through the ranks to seize back command of the ship and claim his revenge. Yet, while the battle for control of the Relentless rages, a sinister alien presence draws ever closer...   Action adventure with the Imperial Navy in the cold reaches of the Eastern Fringe.**', 
        '/uploads/d814d345-97c8-4539-9dde-761531f1c6e9.jpg', 
        '/uploads/d814d345-97c8-4539-9dde-761531f1c6e9.epub', 
