INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        357, 
        'Honour of the Grave', 
        'Robin D. Laws', 
        'As the Empire''s mighty armies clash against the rampaging hordes of evil, they leave in their wake the detritus of war, including the dead and the dying. Resourceful Angelika Fleischer ekes a living by looting the bloody battlefields, searching for the trinkets and gold carried by soldiers of all sides. But an encounter with the mysterious Kopf brothers leaves Angelika desperate to discover the dark truth behind their quest to find their missing brother before the sweeping tide of battle overtakes them all.Review''Dark tales from a brutal world'' - Starlog ''An explosive and hugely entertaining mixture of dark fantasy, intrigue and gory action'' - SFX About the AuthorRobin D Laws is an acclaimed designer of games, perhaps best known for the roleplaying games ''Feng Shui'', ''Dying Earth'' and ''Rune''. He has also worked on computer and collectible card games and is currently a columnist for Dragon magazine. Just recently, Robin began working as a writer for Marvel Comics, including an Iron Man story arc and the upcoming mini series Hulk: Nightmaria. Honour of the Grave is Robin''s third fantasy novel.', 
        '/uploads/d7b4ebe3-39eb-4646-95ed-6364dcf29a27.jpg', 
        '/uploads/d7b4ebe3-39eb-4646-95ed-6364dcf29a27.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
