INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        386, 
        'Reaper', 
        'Sarah Cawkwell', 
        'Empire Captain Kale von Kessel lies dying upon the field of battle after a doomed defence against the forces of Chaos. As the enemy leader – the infamous consort of Khorne, Valkia the Bloody – approaches to claim his head in the name of her dark master, von Kessel realises that his life of battle has been leading to this moment, and that Valkia wants more than just his head – she has been sent to claim his very soul.ABOUT THE BOOKA Valkia the Bloody short story by S P Cawkwell. Previously published in the Black Library Live! 2012 Chapbook.', 
        '/uploads/9168a9dd-0022-48f7-b9fa-1b3ea6a4967b.jpg', 
        '/uploads/9168a9dd-0022-48f7-b9fa-1b3ea6a4967b.epub', 
