INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        389, 
        'Lord of the Night', 
        'Simon Spurrier', 
        'This gripping new novel from the author of the action-packed Fire Warrior is sure to set pulses racing as it reveals the horrific, war-torn future of Warhammer 40,000 from the point of view of the forces of evil! Commander Sahaal of the Night Lords Chaos Space Marines is a walking nightmare in power armour. Driven by ten thousand years of hatred and bitterness, his goal is an ancient relic that will help him reclaim dominion over his armies. The only person standing in his way is Mita Ashyn, a young, idealistic telepath and agent on the Inquisition of the Imperium. Set on the teeming hive world of Equixus, both opponents begin to realise they can''t even trust their own comrades when ultimate power is up for grabs.**Review"''Great SF from a very dark future.'' Starlog" About the AuthorSimon Spurrier has few insightful recollections from his wild youth because he''s still in the middle of it. Since discovering that depressing the buttons on a keyboard could create all manner of interesting squiggles on a screen, he''s become a frequent contributor to cult comic 2000 AD and the Black Library.', 
        '/uploads/7ed361bd-be58-4c77-a423-bda3eab971b1.jpg', 
        '/uploads/7ed361bd-be58-4c77-a423-bda3eab971b1.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
