INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        411, 
        'Farseer', 
        'William King', 
        'The eldar farseers can see the future - or more particularly, the futures. Endless possibilities stretch ahead of the galaxy. By manipulating events, the eldar can bring peace, for a time. But they are not powerful anymore - so they must find an agent. They must find one very special human being.From Publishers WeeklyA destitute, half-mad spaceship captain and a Farseer team up to battle dark forces in William King''s whirlwind adventure. When Auric, an elf-like seer, visits Janus Darke in a drug-ridden dive, tells him that their futures are entwined and offers him a fortune to journey into the deadly Eye of Terror, Janus writes Auric off as insane. Still, Janus goes along with Auric''s plan and soon finds himself contending with a powerful force that is determined to steal the one thing he has left to lose his soul. Although the political structure of King''s (Dragonslayer) fanciful world never fully comes into focus, he paints a bleak but compelling portrait of life in the 41st century. Copyright 2002 Cahners Business Information, Inc.', 
        '/uploads/450449d1-f527-4cfc-9f51-fcb6d7b2e8ae.jpg', 
        '/uploads/450449d1-f527-4cfc-9f51-fcb6d7b2e8ae.epub', 
        'epub', 
