INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        419, 
        'Skavenslayer', 
        'William King', 
        'Review''Fantastic scenarios.'' Daily Telegraph ''The King of high adventure.'' Starlog ''He presents an action-packed life of fantasy axe-swinging'' SFX Product DescriptionSet in the mighty city of Nuln, Gotrek and Felix are back in Skavenslayer, the second novel in this epic saga. Seeking to undermine the very fabric of the Empire with their arcane warp-sorcery, the skaven, twisted Chaos rat-men, are at large in the reeking sewers beneath the city. Led by Grey Seer Thanquol, the servants of the Horned Rat are determined to overthrow this bastion of humanity. Against such forces, what possible threat can just two hard-bitten adventurers pose?', 
        '/uploads/2e3e96fa-3344-49e5-8044-3bde765a65af.jpg', 
        '/uploads/2e3e96fa-3344-49e5-8044-3bde765a65af.epub', 
