INSERT INTO books (
        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        422, 
        'Sword of Caledor', 
        'William King', 
        'Synopsis:Tyrion – Unparalleled swordsman and tactician.Teclis – Greatest natural sorcerer of the age, his power rivalling that of fabled Caledor.Together these twins are the greatest high elf heroes to still walk the earth.Tyrion and Teclis venture into the deadly jungles of Lustria on a desperate hunt for the lost sword of Caledor Dragontamer, the fabled Sunfang. While they search for this ancient artefact, the Witch King Malekith continues his assault on Ulthuan, sending the deadly assassin Urian Poisonblade to kill the Everqueen. And in the Realm of Chaos, the sorceress Morathi makes a pact with another enemy of Tyrion and Teclis – the sinister daemon N’Kari.Biography:William King was born in Stranraer, Scotland, in 1959. His short stories have appeared in ''The Year''s Best SF'', ''Zenth'', ''White Dwarf'' and ''Interzone''.He has travelled extensively throughout Europe and Asia, but he currently lives in Prague. His works for Black Library include the first seven Gotrek &amp; Felix novels, the tale of Ragnar Blackmane and the forthcoming Tyrion and Teclis trilogy', 
        '/uploads/c2ba9da3-1448-4787-a1a5-309e7f0f2ddb.jpg', 
        '/uploads/c2ba9da3-1448-4787-a1a5-309e7f0f2ddb.epub', 
        'epub', 
        'published', 
        'public', 
        'education', 
        0, 
        'approved'
    );
