        id, title, author, description, cover_image_url, file_url, file_type, 
        status, visibility, channel_type, is_user_submission, submission_status
    ) VALUES (
        425, 
        'Trollslayer', 
        'William King', 
        'Review''The finely crafted adventures of two very differrent characters.'' - SFX ''A very gripping tale.'' - Starlog Product DescriptionTrollslayer is the first part of the death saga of Gotrek Gurnisson, as retold by his travelling companion Felix Jaeger. Set in the darkly gothic world of Warhammer, Trollslayer is an episodic novel featuring some of the most extraordinary adventures of this deadly pair of heroes. Monsters, daemons, sorcerers, mutants, orcs, beastmen and worse are to be found as Gotrek strives to achieve a noble death in battle. Felix, of course, only has to survive to tell the tale.', 
        '/uploads/0776a8cc-fef6-47f0-983f-3684780b5d06.jpg', 
        '/uploads/0776a8cc-fef6-47f0-983f-3684780b5d06.epub', 
